import React, { useState, useRef, useEffect } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '../components/ui/card';
import { Button } from '../components/ui/button';
import { Input } from '../components/ui/input';
import { Label } from '../components/ui/label';
import { Textarea } from '../components/ui/textarea';
import { Badge } from '../components/ui/badge';
import { Avatar, AvatarFallback, AvatarImage } from '../components/ui/avatar';
import { useAuth } from '../contexts/AuthContext';
import { 
  User, Phone, Edit, Camera, Mail, Calendar, 
  Shield, Heart, MapPin, CheckCircle2, 
  Upload, Save, X, CreditCard, Stethoscope, 
  DollarSign, Award, Settings, Star
} from 'lucide-react';
import LoadingSpinner from '../components/ui/LoadingSpinner';
import { Progress } from '../components/ui/progress';
import { toast } from 'sonner';

// Mock UserService for cases where the service doesn't exist
const UserService = {
  updateProfile: async (id, data) => {
    // Mock implementation - in real app this would make API call
    console.log('Updating profile:', id, data);
    return Promise.resolve(data);
  }
};

// Reusable components - moved outside to prevent re-creation
const ProfileHeader = ({ title, subtitle, gradient }) => (
  <div className="text-center space-y-2">
    <h1 className={`text-4xl font-bold bg-gradient-to-r ${gradient} bg-clip-text text-transparent`}>
      {title}
    </h1>
    <p className="text-gray-600 text-lg">{subtitle}</p>
  </div>
);

const CompletionCard = ({ completion, gradient, icon: Icon, title, subtitle }) => (
  <Card className={`border-0 shadow-xl bg-gradient-to-r ${gradient} text-white`}>
    <CardContent className="p-6">
      <div className="flex items-center justify-between mb-4">
        <div className="flex items-center gap-3">
          <div className="p-2 bg-white/20 rounded-full">
            <Icon className="w-6 h-6" />
          </div>
          <div>
            <h3 className="text-xl font-semibold">{title}</h3>
            <p className="opacity-90">{subtitle}</p>
          </div>
        </div>
        <div className="text-right">
          <div className="text-3xl font-bold">{completion}%</div>
          <div className="text-sm opacity-90">Complete</div>
        </div>
      </div>
      <Progress value={completion} className="h-3 bg-white/20" />
    </CardContent>
  </Card>
);

const AvatarSection = ({ gradient, roleId, badgeIcon: BadgeIcon, badgeText, secondaryBadge, isEditing, avatarPreview, formData, fileInputRef, handleAvatarUpload }) => (
  <div className="flex flex-col items-center space-y-4">
    <div className="relative group">
      <Avatar className={`h-32 w-32 border-4 ${gradient} shadow-2xl`}>
        <AvatarImage src={avatarPreview || formData.avatar} className="object-cover" />
        <AvatarFallback className={`text-3xl bg-gradient-to-br ${gradient.replace('border-', '')} text-white`}>
          {formData.name?.split(' ').map(n => n[0]).join('').toUpperCase() || 'U'}
        </AvatarFallback>
      </Avatar>
      {isEditing && (
        <div 
          className="absolute inset-0 bg-black/50 rounded-full flex items-center justify-center cursor-pointer opacity-0 group-hover:opacity-100 transition-opacity"
          onClick={() => fileInputRef.current?.click()}
        >
          <Camera className="w-8 h-8 text-white" />
        </div>
      )}
    </div>
    {isEditing && (
      <Button variant="outline" size="sm" onClick={() => fileInputRef.current?.click()}>
        <Upload className="w-4 h-4 mr-2" />Upload Photo
      </Button>
    )}
    <input ref={fileInputRef} type="file" accept="image/*" onChange={handleAvatarUpload} className="hidden" />
    
    <div className="bg-gradient-to-r from-emerald-500 to-teal-600 text-white px-4 py-2 rounded-full flex items-center gap-2 shadow-lg">
      <BadgeIcon className="w-4 h-4" />
      <span className="font-semibold text-sm">ID: {roleId}</span>
    </div>
    {secondaryBadge && secondaryBadge}
  </div>
);

const FormField = ({ label, icon: Icon, value, displayValue, onChange, type = "text", options, isTextarea, readOnly, placeholder, fieldKey, isEditing }) => {
  const inputId = `field_${fieldKey}`;
  
  return (
    <div className="space-y-2">
      <Label htmlFor={inputId} className="text-sm font-semibold text-gray-700 flex items-center gap-2">
        <Icon className="w-4 h-4" />
        {label}
      </Label>
      {isEditing && !readOnly ? (
        type === "select" ? (
          <select
            id={inputId}
            value={value || ''}
            onChange={(e) => onChange(e.target.value)}
            className="w-full h-12 px-3 border-2 focus:border-blue-500 rounded-lg bg-white"
          >
            <option value="">Select {label.toLowerCase()}</option>
            {options?.map(opt => <option key={opt} value={opt}>{opt}</option>)}
          </select>
        ) : isTextarea ? (
          <Textarea
            id={inputId}
            value={value || ''}
            onChange={(e) => onChange(e.target.value)}
            className="w-full h-24 px-3 py-2 border-2 focus:border-blue-500 rounded-lg resize-none"
            placeholder={placeholder}
          />
        ) : (
          <Input
            id={inputId}
            type={type}
            value={value || ''}
            onChange={(e) => onChange(e.target.value)}
            className="h-12 border-2 focus:border-blue-500 rounded-lg"
            placeholder={placeholder}
          />
        )
      ) : (
        <div className="h-12 px-3 py-2 bg-gray-50 border-2 border-gray-100 rounded-lg flex items-center">
          <span className="font-medium text-gray-800">{displayValue || value || 'Not provided'}</span>
        </div>
      )}
    </div>
  );
};

export default function ProfileSettings() {
  const { user, updateUser } = useAuth();
  const [isEditing, setIsEditing] = useState(false);
  const [loading, setLoading] = useState(true);
  const [avatarPreview, setAvatarPreview] = useState(user?.avatar || null);
  const [isUploading, setIsUploading] = useState(false);
  const fileInputRef = useRef(null);
  
  const userRole = user?.role;
  const isPatient = userRole === 'patient';
  const isDoctor = userRole === 'doctor';
  const isAdmin = userRole === 'admin';

  // Generate unique IDs
  const generateId = (prefix) => {
    const year = new Date().getFullYear();
    const random = Math.floor(Math.random() * 10000).toString().padStart(4, '0');
    return `${prefix}${year}${random}`;
  };

  // Initialize form data based on user role
  const getInitialFormData = () => {
    const baseData = {
      name: user?.name || '',
      email: user?.email || '',
      phone: user?.phone || '',
      avatar: user?.avatar || ''
    };

    if (isPatient) {
      return {
        ...baseData,
        patient_id: user?.patient_id || generateId('PAT'),
        age: user?.age || '',
        gender: user?.gender || '',
        blood_type: user?.blood_type || '',
        emergency_contact: user?.emergency_contact || '',
        address: user?.address || '',
        date_of_birth: user?.date_of_birth || user?.dateOfBirth || '',
        medical_history: user?.medical_history || user?.medicalHistory || [],
        allergies: user?.allergies || []
      };
    } 
    
    if (isDoctor) {
      return {
        ...baseData,
        doctor_id: user?.doctor_id || generateId('DOC'),
        specialization: user?.specialization || user?.specialty || '',
        experience: user?.experience || '',
        hospital: user?.hospital || '',
        consultation_fee: user?.consultation_fee || user?.consultationFee || '',
        about: user?.about || user?.bio || '',
        license_number: user?.license_number || user?.licenseNumber || '',
        rating: user?.rating || 0,
        reviews: user?.reviews || 0
      };
    }
    
    if (isAdmin) {
      return {
        ...baseData,
        admin_id: user?.admin_id || user?.id || generateId('ADM'),
        role: user?.adminRole || 'System Administrator',
        department: user?.department || 'IT Operations',
        permissions: user?.permissions || ['user_management', 'system_config', 'reports']
      };
    }
    
    return baseData;
  };

  const [formData, setFormData] = useState(getInitialFormData);

  useEffect(() => {
    if (user && loading) {
      setFormData(getInitialFormData());
      setAvatarPreview(user?.avatar || null);
      setLoading(false);
    }
  }, [user, loading]);

  // Calculate profile completion
  const calculateProfileCompletion = () => {
    const requiredFields = {
      patient: ['name', 'phone', 'age', 'gender', 'blood_type', 'emergency_contact', 'address', 'date_of_birth'],
      doctor: ['name', 'phone', 'specialization', 'experience', 'hospital', 'consultation_fee', 'about'],
      admin: ['name', 'phone', 'role', 'department']
    };
    
    const fields = requiredFields[userRole] || [];
    const filledFields = fields.filter(field => {
      const value = formData[field];
      return Array.isArray(value) ? value.length > 0 : value && value.toString().trim();
    });
    
    return fields.length ? Math.round((filledFields.length / fields.length) * 100) : 0;
  };

  const handleAvatarUpload = (event) => {
    const file = event.target.files[0];
    if (!file) return;
    
    if (!file.type.startsWith('image/')) {
      toast.error('Please select a valid image file.');
      return;
    }
    
    if (file.size > 5 * 1024 * 1024) {
      toast.error('File size must be less than 5MB.');
      return;
    }
    
    const reader = new FileReader();
    reader.onload = (e) => {
      setAvatarPreview(e.target.result);
      setFormData(prev => ({ ...prev, avatar: e.target.result }));
    };
    reader.readAsDataURL(file);
  };

  const handleSave = async () => {
    setIsUploading(true);
    try {
      const roleMessages = {
        patient: 'Patient profile updated successfully! 🎉',
        doctor: 'Doctor profile updated successfully! 🎉',
        admin: 'Admin profile updated successfully! 🎉'
      };
      
      const updatedUserData = { ...formData };
      
      // Update via UserService if available
      try {
        if (user?.id && UserService.updateProfile) {
          await UserService.updateProfile(user.id, updatedUserData);
        }
      } catch (serviceError) {
        console.log('UserService update failed, updating local state:', serviceError);
      }
      
      updateUser({ ...user, ...updatedUserData });
      setIsEditing(false);
      toast.success(roleMessages[userRole] || 'Profile updated successfully! 🎉');
      
    } catch (error) {
      console.error('Update error:', error);
      toast.error('Failed to update profile. Please try again.');
    } finally {
      setIsUploading(false);
    }
  };

  const handleInputChange = (field, value) => {
    setFormData(prev => ({ ...prev, [field]: value }));
  };

  const handleCancel = () => {
    setFormData(getInitialFormData());
    setAvatarPreview(user?.avatar || null);
    setIsEditing(false);
  };


  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-96">
        <LoadingSpinner size="lg" text="Loading profile..." />
      </div>
    );
  }

  const profileCompletion = calculateProfileCompletion();
  
  // Role-specific configurations
  const roleConfigs = {
    patient: {
      title: "Patient Profile",
      subtitle: "Manage your personal and medical information",
      gradient: "from-blue-600 to-purple-600",
      cardGradient: "from-blue-500 to-purple-600",
      avatarGradient: "border-gradient-to-br from-blue-400 to-purple-500",
      icon: User,
      badgeIcon: CreditCard,
      roleId: formData.patient_id
    },
    doctor: {
      title: "Doctor Profile",
      subtitle: "Manage your professional information and practice details",
      gradient: "from-green-600 to-emerald-600",
      cardGradient: "from-green-500 to-emerald-600", 
      avatarGradient: "border-gradient-to-br from-green-400 to-emerald-500",
      icon: Stethoscope,
      badgeIcon: Award,
      roleId: formData.doctor_id,
      secondaryBadge: (
        <div className="bg-gradient-to-r from-yellow-500 to-orange-500 text-white px-4 py-2 rounded-full flex items-center gap-2 shadow-lg">
          <Star className="w-4 h-4" />
          <span className="font-semibold text-sm">{formData.rating} ⭐ ({formData.reviews} reviews)</span>
        </div>
      )
    },
    admin: {
      title: "Admin Profile",
      subtitle: "Manage your administrative account and system access",
      gradient: "from-purple-600 to-indigo-600",
      cardGradient: "from-purple-500 to-indigo-600",
      avatarGradient: "border-gradient-to-br from-purple-400 to-indigo-500", 
      icon: Shield,
      badgeIcon: Shield,
      roleId: formData.admin_id,
      secondaryBadge: (
        <div className="bg-gradient-to-r from-red-500 to-pink-600 text-white px-4 py-2 rounded-full flex items-center gap-2 shadow-lg">
          <Settings className="w-4 h-4" />
          <span className="font-semibold text-sm">Level: Administrator</span>
        </div>
      )
    }
  };

  const config = roleConfigs[userRole] || roleConfigs.patient;

  // Get role-specific form fields
  const getFormFields = () => {
    const commonFields = [
      { key: 'name', label: 'Full Name', icon: User, placeholder: 'Enter your full name' },
      { key: 'email', label: 'Email Address', icon: Mail, readOnly: true },
      { key: 'phone', label: 'Phone Number', icon: Phone, placeholder: 'Enter your phone number' }
    ];

    const roleFields = {
      patient: [
        ...commonFields,
        { key: 'age', label: 'Age', icon: Calendar, type: 'number', placeholder: 'Enter your age', format: (val) => val ? `${val} years` : 'Not provided' },
        { key: 'gender', label: 'Gender', icon: User, type: 'select', options: ['Male', 'Female', 'Other'] },
        { key: 'date_of_birth', label: 'Date of Birth', icon: Calendar, type: 'date' },
        { key: 'blood_type', label: 'Blood Type', icon: Heart, type: 'select', options: ['A+', 'A-', 'B+', 'B-', 'AB+', 'AB-', 'O+', 'O-'] },
        { key: 'emergency_contact', label: 'Emergency Contact', icon: Phone, placeholder: 'Emergency contact number' },
        { key: 'address', label: 'Home Address', icon: MapPin, isTextarea: true, placeholder: 'Enter your complete address' }
      ],
      doctor: [
        ...commonFields,
        { key: 'specialization', label: 'Specialization', icon: Stethoscope, placeholder: 'Enter your specialization' },
        { key: 'experience', label: 'Years of Experience', icon: Calendar, type: 'number', placeholder: 'Years of experience', format: (val) => val ? `${val} years` : 'Not provided' },
        { key: 'hospital', label: 'Hospital/Clinic', icon: MapPin, placeholder: 'Hospital or clinic name' },
        { key: 'consultation_fee', label: 'Consultation Fee', icon: DollarSign, type: 'number', placeholder: 'Consultation fee in USD', format: (val) => val ? `$${val}` : 'Not provided' },
        { key: 'license_number', label: 'License Number', icon: Award, readOnly: true },
        { key: 'about', label: 'Professional Summary', icon: User, isTextarea: true, placeholder: 'Describe your experience, expertise, and approach to patient care...' }
      ],
      admin: [
        ...commonFields,
        { key: 'role', label: 'Administrative Role', icon: Shield, placeholder: 'Enter your administrative role' },
        { key: 'department', label: 'Department', icon: MapPin, placeholder: 'Enter your department' }
      ]
    };

    return roleFields[userRole] || roleFields.patient;
  };

  return (
    <div className={`min-h-screen bg-gradient-to-br from-${config.gradient.split('-')[1]}-50 via-white to-${config.gradient.split('-')[3]}-50 -m-6 p-6`}>
      <div className="max-w-6xl mx-auto space-y-8">
        <ProfileHeader title={config.title} subtitle={config.subtitle} gradient={config.gradient} />
        
        <CompletionCard 
          completion={profileCompletion}
          gradient={config.cardGradient}
          icon={CheckCircle2}
          title={isPatient ? "Profile Completion" : isDoctor ? "Professional Profile" : "Administrative Profile"}
          subtitle={isPatient ? "Complete your profile to get better recommendations" : isDoctor ? "Keep your professional information updated" : "Maintain your system administration credentials"}
        />

        <Card className="border-0 shadow-2xl">
          <CardHeader className="pb-4">
            <div className="flex items-center justify-between">
              <CardTitle className="flex items-center gap-3 text-2xl">
                <div className={`p-2 bg-gradient-to-br ${config.cardGradient} rounded-full text-white`}>
                  <config.icon className="w-6 h-6" />
                </div>
                {isPatient ? "Personal Information" : isDoctor ? "Professional Information" : "Administrator Information"}
              </CardTitle>
              <Button 
                variant={isEditing ? "destructive" : "default"}
                size="lg"
                onClick={() => setIsEditing(!isEditing)}
                className={isEditing ? "" : `bg-gradient-to-r ${config.cardGradient} hover:from-${config.cardGradient.split('-')[1]}-600 hover:to-${config.cardGradient.split('-')[3]}-700`}
              >
                {isEditing ? <X className="w-4 h-4 mr-2" /> : <Edit className="w-4 h-4 mr-2" />}
                {isEditing ? 'Cancel' : 'Edit Profile'}
              </Button>
            </div>
          </CardHeader>
          
          <CardContent className="space-y-8">
            <div className="flex flex-col lg:flex-row items-start gap-8">
              <AvatarSection 
                gradient={config.avatarGradient}
                roleId={config.roleId}
                badgeIcon={config.badgeIcon}
                secondaryBadge={config.secondaryBadge}
                isEditing={isEditing}
                avatarPreview={avatarPreview}
                formData={formData}
                fileInputRef={fileInputRef}
                handleAvatarUpload={handleAvatarUpload}
              />
              
              <div className="flex-1 space-y-6">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  {getFormFields().map(field => (
                    <FormField
                      key={field.key}
                      fieldKey={field.key}
                      label={field.label}
                      icon={field.icon}
                      value={formData[field.key]}
                      displayValue={field.format ? field.format(formData[field.key]) : formData[field.key]}
                      onChange={(value) => handleInputChange(field.key, value)}
                      type={field.type}
                      options={field.options}
                      isTextarea={field.isTextarea}
                      readOnly={field.readOnly}
                      placeholder={field.placeholder}
                      isEditing={isEditing}
                    />
                  ))}
                </div>

                {/* Role-specific additional sections */}
                {isPatient && (
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mt-6">
                    <div>
                      <Label className="text-sm font-semibold text-gray-700">Medical History</Label>
                      <div className="mt-2 flex flex-wrap gap-2">
                        {formData.medical_history?.length > 0 ? (
                          formData.medical_history.map((condition, index) => (
                            <Badge key={index} variant="outline" className="text-sm bg-blue-50 text-blue-700">
                              {condition}
                            </Badge>
                          ))
                        ) : <p className="text-gray-500 text-sm">No medical history recorded</p>}
                      </div>
                    </div>
                    <div>
                      <Label className="text-sm font-semibold text-gray-700">Allergies</Label>
                      <div className="mt-2 flex flex-wrap gap-2">
                        {formData.allergies?.length > 0 ? (
                          formData.allergies.map((allergy, index) => (
                            <Badge key={index} variant="outline" className="text-sm bg-red-50 text-red-700">
                              {allergy}
                            </Badge>
                          ))
                        ) : <p className="text-gray-500 text-sm">No known allergies</p>}
                      </div>
                    </div>
                  </div>
                )}

                {isAdmin && (
                  <div>
                    <h3 className="text-xl font-semibold mb-4 flex items-center gap-2 text-gray-800">
                      <Settings className="w-5 h-5 text-orange-600" />
                      System Permissions
                    </h3>
                    <div className="flex flex-wrap gap-2">
                      {formData.permissions?.map((permission, index) => (
                        <Badge key={index} className="bg-orange-100 text-orange-800 px-3 py-1">
                          {permission.replace('_', ' ').toUpperCase()}
                        </Badge>
                      ))}
                    </div>
                  </div>
                )}

                {isEditing && (
                  <div className="flex gap-4 pt-6 border-t">
                    <Button 
                      onClick={handleSave} 
                      disabled={isUploading}
                      className={`bg-gradient-to-r from-green-500 to-emerald-600 hover:from-green-600 hover:to-emerald-700 px-8 py-3 text-lg font-semibold shadow-lg`}
                    >
                      {isUploading ? (
                        <div className="flex items-center gap-2">
                          <div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin" />
                          Saving...
                        </div>
                      ) : (
                        <div className="flex items-center gap-2">
                          <Save className="w-5 h-5" />Save Changes
                        </div>
                      )}
                    </Button>
                    <Button variant="outline" onClick={handleCancel} className="px-8 py-3 text-lg font-semibold border-2">
                      <X className="w-5 h-5 mr-2" />Cancel
                    </Button>
                  </div>
                )}
              </div>
            </div>
          </CardContent>
        </Card>
      </div>
    </div>
  );
}